import axios from 'axios';
export default {
    name: 'autoconf',
    data: function () {
        return {
            settings: {}
        };
    },
    mounted: function () {
        var _this = this;
        axios.get('/api/autoconf')
            .then(function (response) {
            console.log(response);
            _this.settings = response.data;
        })
            .catch(function (error) {
            console.log(error);
        });
    },
    methods: {
        onSubmit: function () {
            var _this = this;
            axios.post('/api/autoconf', this.settings)
                .then(function () {
                _this.$message({
                    showClose: true,
                    duration: 2000,
                    message: '更新成功',
                    type: 'success'
                });
            })
                .catch(function (error) {
                console.log(error);
            });
        },
        clean: function () {
            axios.get('/api/client/clean')
                .then(function (response) {
                console.log(response);
            })
                .catch(function (error) {
                console.log(error);
            });
        },
    }
};
