import axios from 'axios';
export default {
    name: 'scrapingbak',
    data: function () {
        return {
            fileList: [],
            multifile: false
        };
    },
    methods: {
        submitUpload: function () {
            this.$refs.upload.submit();
        },
        exportdb: function () {
            window.location.href = '/api/export';
        },
        cleandata: function () {
            var _this = this;
            axios.get('/api/cleandb')
                .then(function (response) {
                console.log(response);
                _this.$message({
                    showClose: true,
                    duration: 2000,
                    message: '清理成功',
                    type: 'success'
                });
            })
                .catch(function (error) {
                console.log(error);
            });
        }
    }
};
