import axios from 'axios';
export default {
    name: 'config',
    data: function () {
        return {
            loglevel: 20
        };
    },
    mounted: function () {
        var _this = this;
        axios.get('/api/loglevel')
            .then(function (response) {
            console.log(response);
            _this.loglevel = response.data.loglevel;
        })
            .catch(function (error) {
            console.log(error);
        });
    },
    methods: {
        onSubmit: function () {
            var _this = this;
            var data = { loglevel: this.loglevel };
            axios.put('/api/loglevel', data)
                .then(function () {
                _this.$message({
                    showClose: true,
                    duration: 2000,
                    message: '更新成功',
                    type: 'success'
                });
            })
                .catch(function (error) {
                console.log(error);
            });
        },
    }
};
